#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
const ll inf=1e17;
ll n,root,dp[N];
struct node
{
	ll v,w;
};
vector<node> g[N];
void dfs(int u,int f)
{
	if(g[u].size()==1&&root!=u) dp[u]=inf;
	for(int i=0;i<g[u].size();i++)
	{
		node t=g[u][i];
		if(t.v==f) continue;
		dfs(t.v,u);
		dp[u]+=(min(t.w,dp[t.v]));
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>root;
	for(int i=1;i<n;i++)
	{
		ll u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	dfs(root,0);
	cout<<dp[root];
	return 0;
}
